<script>
document.querySelectorAll('.role-card').forEach((card) => {
    card.addEventListener('click', () => {
        document.getElementById('account_role').value = card.dataset.role;
        document.querySelectorAll('.role-card').forEach((item) => {
            item.classList.remove('border-primary', 'ring-2', 'ring-primary');
        });
        card.classList.add('border-primary', 'ring-2', 'ring-primary');
    });
});
</script>
